// Pass 5: block merging.  Re-scan F.begin()..F.end() each iteration to
// be safe with iterator invalidation.
bool mergedSomething = true;
while (mergedSomething) {
  mergedSomething = false;
  // Snapshot the BB list to avoid iterator invalidation.
  std::vector<BasicBlock*> bbs;
  for (auto& bb : F)
    bbs.push_back(&bb);
  for (BasicBlock* bb : bbs) {
    // `bb` might have been erased by a previous merge in this scan; skip.
    if (bb->getTerminator() == nullptr)
      continue;
    if (mergeWithSingleSuccessor(*bb)) {
      mergedSomething = true;
      changed = true;
      break; // restart with fresh BB list
    }
  }
}

action.new_str:
// Pass 5: block merging.  Snapshot the BB list to a vector, then walk
// the snapshot looking for merge candidates.  After every successful
// merge we break, refresh the snapshot and restart.
bool mergedSomething = true;
while (mergedSomething) {
  mergedSomething = false;
  // Iterate using LLVM's iplist iterator, advancing before modifying.
  for (auto it = F.begin(); it != F.end();) {
    BasicBlock& bb = *it;
    ++it;
    if (mergeWithSingleSuccessor(bb)) {
      mergedSomething = true;
      changed = true;
      break; // iterator may be invalid; restart
    }
  }
}

